import{_ as n,o as i,c as r,aq as a}from"./chunks/framework.YYeHXFTf.js";const p=JSON.parse('{"title":"Erste Schritte","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md","lastUpdated":1780293146000}'),t={name:"getting-started.md"};function s(l,e,d,o,h,c){return i(),r("div",null,[...e[0]||(e[0]=[a(`<h1 id="erste-schritte" tabindex="-1">Erste Schritte <a class="header-anchor" href="#erste-schritte" aria-label="Permalink to “Erste Schritte”">​</a></h1><h2 id="einfuhrung" tabindex="-1">Einführung <a class="header-anchor" href="#einfuhrung" aria-label="Permalink to “Einführung”">​</a></h2><p>Skydxddy-Ressourcen sind modulare, leistungsorientierte RedM-Skripte, die für immersive Rollenspielserver entwickelt wurden.</p><p>Jede Ressource ist eigenständig und kann unabhängig installiert werden.</p><p>Diese Dokumentation enthält Installationsanleitungen, Konfigurationshinweise und eine API-Dokumentation für alle offiziellen Skydxddy-Skripte.</p><hr><h2 id="anforderungen" tabindex="-1">Anforderungen <a class="header-anchor" href="#anforderungen" aria-label="Permalink to “Anforderungen”">​</a></h2><p>Bevor Sie Skydxddy-Ressourcen installieren, stellen Sie sicher, dass Ihr Server die folgenden Anforderungen erfüllt:</p><ul><li>Aktiver RedM-Server</li><li>Neueste empfohlene Serverartefakte</li><li>Erforderliches framework falls zutreffend)</li><li>Erforderliches Abhängigkeiten (in jedem Skriptabschnitt aufgeführt)</li><li>MariaDB oder MySQL (falls das Skript eine Datenbank als Speicher verwendet)</li></ul><hr><h2 id="grundlegender-installationsablauf" tabindex="-1">Grundlegender Installationsablauf <a class="header-anchor" href="#grundlegender-installationsablauf" aria-label="Permalink to “Grundlegender Installationsablauf”">​</a></h2><p>Alle Skydxddy-Skripte folgen dem gleichen Installationsmuster:</p><ol><li>Laden Sie die Ressource herunter.</li><li>Platzieren Sie den Ressourcenordner in Ihrem resources/Verzeichnis.</li><li>Fügen Sie den Ressourcennamen zu Ihrem hinzu server.cfg.</li><li>Konfigurieren Sie die Einstellungen innerhalb von config.lua.</li><li>Starten Sie Ihren Server neu.</li></ol><p>Detaillierte Konfigurationsanweisungen finden Sie im Dokumentationsbereich jedes Skripts.</p><hr><h2 id="ordnerstrukturubersicht" tabindex="-1">Ordnerstrukturübersicht <a class="header-anchor" href="#ordnerstrukturubersicht" aria-label="Permalink to “Ordnerstrukturübersicht”">​</a></h2><p>Eine typische Skydxddy-Ressource ist wie folgt strukturiert:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>skydxddy_scriptname/</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├─ client/</span></span>
<span class="line"><span>├─ server/</span></span>
<span class="line"><span>├─ shared/</span></span>
<span class="line"><span>├─ config.lua</span></span>
<span class="line"><span>└─ fxmanifest.lua</span></span></code></pre></div><ul><li><code>client/</code> – Clientseitige Logik</li><li><code>server/</code> – Serverseitige Logik</li><li><code>shared/</code> – Gemeinsame Hilfsprogramme und Konfiguration</li><li><code>config.lua</code> – Skriptkonfiguration</li><li><code>fxmanifest.lua</code> – Ressourcenmanifest</li></ul><p>Diese Struktur gewährleistet Modularität, Übersichtlichkeit und Wartungsfreundlichkeit.</p><hr><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to “Nächste Schritte”">​</a></h2><p>Navigieren Sie im Abschnitt <strong>Scripts</strong> zu dem Skript, das Sie installieren möchten, und folgen Sie der detaillierten Installations- und Konfigurationsanleitung.</p>`,23)])])}const g=n(t,[["render",s]]);export{p as __pageData,g as default};
